#!/bin/bash

# Load audit rule if it doesn't exist
auditctl -D | grep -qE 'type=exec arch=b64 syscall=(open|close|readv|writev) perm=\S+ name="ssh-keysign"' || {
    auditctl -w /usr/bin/ssh-keysign -p x -k privileged_ssh_keysign
}

# Ensure the audit rule is persistent across reboots
cat <<EOF | tee /etc/audit/rules.d/privileged_ssh_keysign.rules
-w /usr/bin/ssh-keysign -p x -k privileged_ssh_keysign
EOF

exit 0
